<?php

/**
 * InvoicetemplatesTable
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 */
class InvoicetemplatesTable extends Doctrine_Table
{
    /**
     * Returns an instance of this class.
     *
     * @return InvoicetemplatesTable The table instance
     */
    public static function getInstance()
    {
        return Doctrine_Core::getTable('Invoicetemplates');
    }

    public static function getInvoiceTemplates()
    {
        $templates = array();

        $templates[] = "";

        $q = Doctrine_Query::create()
           ->from("Invoicetemplates a")
           ->orderBy("a.title ASC");
        $invoices = $q->execute();

        foreach($invoices as $invoice)
        {
            $templates[$invoice->getId()] =  $invoice->getTitle();
        }

        return $templates;
    }
}